parameters.functionCode:
const file = $('Google Drive Trigger').item.json;
const textData = $input.first().json;
const rawText = textData.text || textData.data || '';

// File metadata
const fileName = file.name || 'Untitled';
const fileId = file.id;
const mimeType = file.mimeType || '';
const modifiedTime = file.modifiedTime;

// Content — cap at 8000 chars for embedding safety
const content = `${fileName}\n\n${rawText}`.substring(0, 8000);

// Classify namespace by filename keywords
const lower = fileName.toLowerCase();
let namespace = 'jrih';
if (lower.includes('axiom')) namespace = 'axiom';
else if (lower.includes('lumena')) namespace = 'lumena';
else if (lower.includes('aro')) namespace = 'aro';
else if (lower.includes('hoj') || lower.includes('heart of juniper')) namespace = 'heart_of_juniper';
else if (lower.includes('kintsugi')) namespace = 'jrih';
else if (lower.includes('capital') || lower.includes('realty')) namespace = 'jrih';
else if (lower.includes('personal') || lower.includes('rose')) namespace = 'personal';
else if (lower.includes('intel') || lower.includes('research')) namespace = 'intel';
else if (lower.includes('infra') || lower.includes('ops')) namespace = 'infra';
else if (lower.includes('contract') || lower.includes('invoice')) namespace = 'jrih';

return [{
  json: {
    content,
    title: fileName,
    namespace,
    file_id: fileId,
    mime_type: mimeType,
    modified_time: modifiedTime,
    tags: ['google_drive', namespace, 'document']
  }
}];

